<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
  :root {
    --bg: #1a1a2e;
    --panel: #16213e;
    --board-bg: #0f3460;
    --cell-bg: #1c3a5e;
    --text: #e94560;
    --fg: #eee;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: radial-gradient(circle at 50% 30%, #20213a 0%, #0a0a18 100%);
    color: var(--fg);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 20px;
    user-select: none;
  }
  h1 {
    margin: 0 0 12px;
    font-size: 42px;
    letter-spacing: 4px;
    color: #fff;
    text-shadow: 0 0 12px rgba(233,69,96,0.6);
  }
  .bar {
    display: flex;
    align-items: center;
    gap: 16px;
    margin-bottom: 16px;
  }
  #score {
    background: var(--panel);
    border: 1px solid #2a3a6a;
    padding: 10px 18px;
    border-radius: 8px;
    font-size: 18px;
    min-width: 140px;
    text-align: center;
  }
  #score span { color: #ffd369; font-weight: bold; }
  #reset {
    background: linear-gradient(135deg, #e94560, #b5304a);
    color: #fff;
    border: none;
    padding: 10px 20px;
    border-radius: 8px;
    font-size: 16px;
    cursor: pointer;
    transition: transform 0.1s, box-shadow 0.2s;
    box-shadow: 0 4px 12px rgba(233,69,96,0.3);
  }
  #reset:hover { transform: translateY(-1px); box-shadow: 0 6px 16px rgba(233,69,96,0.5); }
  #reset:active { transform: translateY(1px); }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 90px);
    grid-template-rows: repeat(4, 90px);
    gap: 10px;
    background: var(--board-bg);
    padding: 10px;
    border-radius: 10px;
    box-shadow: 0 10px 40px rgba(0,0,0,0.5), inset 0 0 0 1px #2a3a6a;
  }
  .cell {
    background: var(--cell-bg);
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 30px;
    font-weight: bold;
    color: #fff;
    transition: transform 0.08s ease;
  }
  .cell.empty { color: transparent; }
  .v2 { background: #2b4c7e; }
  .v4 { background: #3a6ea5; }
  .v8 { background: #4a89c7; color: #fff; }
  .v16 { background: #5aa3d9; }
  .v32 { background: #f2a65a; }
  .v64 { background: #f2855a; }
  .v128 { background: #e94560; font-size: 26px; }
  .v256 { background: #c8336e; font-size: 26px; }
  .v512 { background: #9b2ec4; font-size: 26px; }
  .v1024 { background: #6a1b9a; font-size: 22px; }
  .v2048 { background: #ffd369; color: #1a1a2e; font-size: 22px; box-shadow: 0 0 20px rgba(255,211,105,0.7); }
  .v4096, .v8192 { background: #fff; color: #1a1a2e; font-size: 20px; }
  .hint { margin-top: 14px; color: #8899bb; font-size: 13px; }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="bar">
    <div id="score">SCORE: <span id="scoreVal">0</span></div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div class="hint">Use arrow keys to move tiles.</div>

<script>
(function () {
  const SIZE = 4;
  let grid = [];      // 2D array, 0 = empty
  let currentScore = 0;

  function makeEmpty() {
    const g = [];
    for (let r = 0; r < SIZE; r++) {
      g.push(new Array(SIZE).fill(0));
    }
    return g;
  }

  function clone(g) {
    return g.map(row => row.slice());
  }

  function boardsEqual(a, b) {
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        if (a[r][c] !== b[r][c]) return false;
      }
    }
    return true;
  }

  function emptyCells(g) {
    const cells = [];
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        if (g[r][c] === 0) cells.push([r, c]);
      }
    }
    return cells;
  }

  function spawnTile(g) {
    const cells = emptyCells(g);
    if (cells.length === 0) return false;
    const [r, c] = cells[Math.floor(Math.random() * cells.length)];
    g[r][c] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  // Slide+merge a single line to the left. Returns { line, gained }.
  function slideLineLeft(line) {
    const nums = line.filter(v => v !== 0);
    const result = [];
    let gained = 0;
    let i = 0;
    while (i < nums.length) {
      if (i + 1 < nums.length && nums[i] === nums[i + 1]) {
        const merged = nums[i] * 2;
        result.push(merged);
        gained += merged;
        i += 2; // each tile merges at most once
      } else {
        result.push(nums[i]);
        i += 1;
      }
    }
    while (result.length < SIZE) result.push(0);
    return { line: result, gained };
  }

  // Extract columns as rows for up/down transforms
  function getColumns(g) {
    const cols = [];
    for (let c = 0; c < SIZE; c++) {
      const col = [];
      for (let r = 0; r < SIZE; r++) col.push(g[r][c]);
      cols.push(col);
    }
    return cols;
  }

  function setColumns(g, cols) {
    for (let c = 0; c < SIZE; c++) {
      for (let r = 0; r < SIZE; r++) g[r][c] = cols[c][r];
    }
  }

  function moveLeft(g) {
    let gained = 0;
    const newG = clone(g);
    for (let r = 0; r < SIZE; r++) {
      const res = slideLineLeft(newG[r]);
      newG[r] = res.line;
      gained += res.gained;
    }
    return { grid: newG, gained };
  }

  function moveRight(g) {
    let gained = 0;
    const newG = clone(g);
    for (let r = 0; r < SIZE; r++) {
      const reversed = newG[r].slice().reverse();
      const res = slideLineLeft(reversed);
      newG[r] = res.line.reverse();
      gained += res.gained;
    }
    return { grid: newG, gained };
  }

  function moveUp(g) {
    let gained = 0;
    const cols = getColumns(g);
    const newCols = [];
    for (let c = 0; c < SIZE; c++) {
      const res = slideLineLeft(cols[c]);
      newCols.push(res.line);
      gained += res.gained;
    }
    const newG = clone(g);
    setColumns(newG, newCols);
    return { grid: newG, gained };
  }

  function moveDown(g) {
    let gained = 0;
    const cols = getColumns(g);
    const newCols = [];
    for (let c = 0; c < SIZE; c++) {
      const reversed = cols[c].slice().reverse();
      const res = slideLineLeft(reversed);
      newCols.push(res.line.reverse());
      gained += res.gained;
    }
    const newG = clone(g);
    setColumns(newG, newCols);
    return { grid: newG, gained };
  }

  // Rendering
  const boardEl = document.getElementById('board');
  const scoreValEl = document.getElementById('scoreVal');

  function buildCells() {
    boardEl.innerHTML = '';
    for (let i = 0; i < SIZE * SIZE; i++) {
      const div = document.createElement('div');
      div.className = 'cell empty';
      boardEl.appendChild(div);
    }
  }

  function render() {
    const cells = boardEl.children;
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const idx = r * SIZE + c;
        const cell = cells[idx];
        const v = grid[r][c];
        cell.className = 'cell';
        if (v === 0) {
          cell.classList.add('empty');
          cell.textContent = '';
        } else {
          cell.classList.add('v' + v);
          cell.textContent = v;
        }
      }
    }
    scoreValEl.textContent = currentScore;
  }

  function reset() {
    grid = makeEmpty();
    currentScore = 0;
    spawnTile(grid);
    spawnTile(grid);
    render();
  }

  function move(direction) {
    let result;
    switch (direction) {
      case 'left': result = moveLeft(grid); break;
      case 'right': result = moveRight(grid); break;
      case 'up': result = moveUp(grid); break;
      case 'down': result = moveDown(grid); break;
      default: return false;
    }
    if (boardsEqual(grid, result.grid)) {
      return false;
    }
    grid = result.grid;
    currentScore += result.gained;
    spawnTile(grid);
    render();
    return true;
  }

  // Keyboard
  window.addEventListener('keydown', function (e) {
    let dir = null;
    switch (e.key) {
      case 'ArrowLeft': dir = 'left'; break;
      case 'ArrowRight': dir = 'right'; break;
      case 'ArrowUp': dir = 'up'; break;
      case 'ArrowDown': dir = 'down'; break;
    }
    if (dir) {
      e.preventDefault();
      move(dir);
    }
  });

  document.getElementById('reset').addEventListener('click', reset);

  // Public API
  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: function () {
      return grid.map(row => row.slice());
    },
    setBoard: function (arr) {
      // set grid exactly, no spawn, no score change
      grid = arr.map(row => row.slice());
      render();
    },
    score: function () {
      return currentScore;
    }
  };

  // Init
  buildCells();
  reset();
})();
</script>
</body>
</html>
